function stripHtml(html) {
  return String(html || "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<\/div>/gi, "\n")
    .replace(/<\/li>/gi, "\n")
    .replace(/<li[^>]*>/gi, "- ")
    .replace(/<[^>]+>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, "\"")
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'")
    .replace(/&#(\d+);/g, (_, n) => {
      try {
        return String.fromCharCode(Number(n));
      } catch (e) {
        return "";
      }
    })
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function firstNonEmpty(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;

    const text = String(value).trim();

    if (text) return text;
  }

  return "";
}

function normalizeText(value) {
  return String(value || "")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function normalizeSubject(value) {
  return String(value || "")
    .replace(/^\s*(RE|RV|FW|FWD)\s*:\s*/gi, "")
    .replace(/\s+/g, " ")
    .trim();
}

function removeAccents(value) {
  return String(value || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function extractEmailAddress(value) {
  if (!value) return "";

  if (typeof value === "string") {
    const match = value.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
    return match ? match[0] : value.trim();
  }

  if (value.address) return value.address;
  if (value.email) return value.email;
  if (value.text) return extractEmailAddress(value.text);

  if (Array.isArray(value.value) && value.value[0]?.address) {
    return value.value[0].address;
  }

  if (Array.isArray(value) && value[0]) {
    return extractEmailAddress(value[0]);
  }

  return "";
}

function sanitizeCaseId(value) {
  let text = String(value || "").trim();

  text = text
    .replace(/[.,;:)\]}]+$/g, "")
    .replace(/^[([{]+/g, "")
    .trim();

  text = removeAccents(text);

  text = text.replace(/[^\w\-]+/g, "_");
  text = text.replace(/_+/g, "_");
  text = text.replace(/^_+|_+$/g, "");

  if (!text) return "";

  // Evita capturas absurdas como "C", que ocurría con "Código".
  if (text.length < 3) return "";

  const badValues = [
    "proyecto",
    "codigo",
    "case_id",
    "id",
    "follow",
    "followup",
    "triaje",
    "cuestionario",
    "questionnaire",
    "respuesta",
    "correo"
  ];

  if (badValues.includes(text.toLowerCase())) return "";

  return text;
}

function extractCaseId(subject, body, attachmentNames = []) {
  const s = String(subject || "");
  const b = String(body || "");
  const combined = `${s}\n${b}\n${attachmentNames.join("\n")}`;

  const patterns = [
    // Follow-up
    /\[Follow-up\]\s*([^\n\r\]\[]+)/i,
    /\[FOLLOWUP\]\s*([^\n\r\]\[]+)/i,
    /\[Followup\]\s*([^\n\r\]\[]+)/i,

    // Triaje / Cuestionario en asunto
    /\[Triaje\]\s*([^\n\r]+)/i,
    /\[Cuestionario\]\s*([^\n\r]+)/i,
    /\[Questionnaire\]\s*([^\n\r]+)/i,

    // Campos explícitos
    /case[_\s-]*id\s*[:=\-]\s*([^\n\r]+)/i,
    /CASE_ID\s*[:=\-]\s*([^\n\r]+)/i,

    /c[oó]digo\s+del\s+proyecto\s*[:=\-]\s*([^\n\r]+)/i,
    /codigo\s+del\s+proyecto\s*[:=\-]\s*([^\n\r]+)/i,
    /proyecto\s*[:=\-]\s*([^\n\r]+)/i,

    // Texto del correo de follow-up generado por el flujo
    /durante\s+el\s+an[aá]lisis\s+del\s+cuestionario\s+de\s+seguridad\s+del\s+proyecto\s+([A-Za-z0-9_\-]+)/i,

    // Fallbacks conocidos del caso anonimizado
    /\b(Codigo_del_proyecto[A-Za-z0-9_\-]*)\b/i,
    /\b(C[oó]digo_del_proyecto[A-Za-z0-9_\-]*)\b/i
  ];

  for (const pattern of patterns) {
    const match = combined.match(pattern);

    if (!match) continue;

    const candidate = sanitizeCaseId(match[1]);

    if (candidate) return candidate;
  }

  return "";
}

function getHeaderValue(headers, name) {
  if (!headers) return "";

  const target = name.toLowerCase();

  if (Array.isArray(headers)) {
    const found = headers.find(h =>
      String(h.name || h.key || "").toLowerCase() === target
    );

    return found?.value || "";
  }

  if (typeof headers === "object") {
    for (const [key, value] of Object.entries(headers)) {
      if (String(key).toLowerCase() === target) {
        return value;
      }
    }
  }

  return "";
}

function getSubject(json) {
  return firstNonEmpty(
    json.subject,
    json.email_subject,
    json.headers?.subject,
    getHeaderValue(json.headers, "subject"),
    json.envelope?.subject
  );
}

function getHtml(json) {
  return firstNonEmpty(
    json.html,
    json.htmlBody,
    json.bodyHtml,
    json.body?.html,
    json.message?.html
  );
}

function getBody(json, html) {
  return normalizeText(firstNonEmpty(
    json.text,
    json.textPlain,
    json.plainText,
    json.bodyText,
    json.body?.text,
    json.body?.plain,
    json.message?.text,
    json.message?.plain,
    json.body,
    stripHtml(html)
  ));
}

function getFromEmail(json) {
  return extractEmailAddress(
    json.from ||
    json.sender ||
    json.headers?.from ||
    getHeaderValue(json.headers, "from") ||
    json.envelope?.from
  );
}

function filenameLooksExcel(filename) {
  const name = String(filename || "").toLowerCase();

  if (!name) return false;
  if (name.startsWith("~$")) return false;

  return (
    name.endsWith(".xlsx") ||
    name.endsWith(".xls") ||
    name.endsWith(".xlsm")
  );
}

function mimeLooksExcel(mimeType) {
  const mime = String(mimeType || "").toLowerCase();

  return (
    mime.includes("spreadsheet") ||
    mime.includes("excel") ||
    mime.includes("vnd.ms-excel") ||
    mime.includes("vnd.openxmlformats-officedocument.spreadsheetml.sheet")
  );
}

async function extractExcelAttachmentB64() {
  const item = $input.item;
  const binary = item.binary || {};
  const keys = Object.keys(binary);

  const attachments = [];

  for (const key of keys) {
    const b = binary[key] || {};

    const filename = firstNonEmpty(
      b.fileName,
      b.filename,
      b.name,
      key
    );

    const mimeType = firstNonEmpty(
      b.mimeType,
      b.mime,
      b.contentType
    );

    const fileExtension = firstNonEmpty(
      b.fileExtension,
      filename.split(".").pop()
    );

    attachments.push({
      key,
      filename,
      mimeType,
      fileExtension,
      is_excel:
        filenameLooksExcel(filename) ||
        mimeLooksExcel(mimeType) ||
        ["xlsx", "xls", "xlsm"].includes(String(fileExtension || "").toLowerCase())
    });
  }

  const excel = attachments.find(a => a.is_excel);

  if (!excel) {
    return {
      attachment_b64: "",
      attachment_filename: "",
      attachment_binary_key: "",
      attachments,
      has_excel_attachment: false
    };
  }

  let buffer;

  try {
    buffer = await this.helpers.getBinaryDataBuffer(0, excel.key);
  } catch (e) {
    throw new Error(
      `Se detectó un adjunto Excel (${excel.filename}) pero no se pudo leer el binario '${excel.key}': ${e.message}`
    );
  }

  return {
    attachment_b64: buffer.toString("base64"),
    attachment_filename: excel.filename,
    attachment_binary_key: excel.key,
    attachments,
    has_excel_attachment: true
  };
}

function detectMailType(subject, body, hasExcelAttachment) {
  const s = normalizeSubject(subject);
  const combined = `${s}\n${body}`.toLowerCase();

  if (
    /\[follow-up\]/i.test(s) ||
    /\[followup\]/i.test(s) ||
    combined.includes("aclaración requerida") ||
    combined.includes("aclaracion requerida") ||
    combined.includes("follow-up") ||
    combined.includes("followup_round") ||
    combined.includes("responded manteniendo el identificador de cada pregunta")
  ) {
    return "followup";
  }

  if (
    /cuestionario/i.test(s) ||
    /questionnaire/i.test(s) ||
    hasExcelAttachment
  ) {
    return "cuestionario";
  }

  if (
    /triaje/i.test(s) ||
    combined.includes("código del proyecto") ||
    combined.includes("codigo del proyecto") ||
    combined.includes("nombre de la contratación") ||
    combined.includes("nombre de la contratacion") ||
    combined.includes("línea de negocio") ||
    combined.includes("linea de negocio") ||
    combined.includes("tipo de información") ||
    combined.includes("tipo de informacion")
  ) {
    return "triaje";
  }

  return "unknown";
}

function fallbackCaseId(mailType, subject, body, attachmentNames = []) {
  const normalizedSubject = normalizeSubject(subject);

  const possible = extractCaseId(normalizedSubject, body, attachmentNames);

  if (possible) return possible;

  return "";
}

const json = $json || {};

const subject = getSubject(json);
const normalizedSubject = normalizeSubject(subject);

const html = getHtml(json);
const body = getBody(json, html);
const fromEmail = getFromEmail(json);

const attachmentInfo = await extractExcelAttachmentB64();

let caseId = extractCaseId(
  normalizedSubject,
  body,
  attachmentInfo.attachments.map(a => a.filename)
);

let mailType = detectMailType(
  normalizedSubject,
  body,
  attachmentInfo.has_excel_attachment
);

if (!caseId) {
  caseId = fallbackCaseId(
    mailType,
    normalizedSubject,
    body,
    attachmentInfo.attachments.map(a => a.filename)
  );
}

const bodyB64 = Buffer.from(body || "", "utf8").toString("base64");
const subjectB64 = Buffer.from(normalizedSubject || "", "utf8").toString("base64");

const warnings = [];

if (!mailType || mailType === "unknown") {
  warnings.push("No se ha podido clasificar el correo como triaje, cuestionario o follow-up.");
}

if (!caseId) {
  warnings.push("No se ha podido extraer case_id del asunto, cuerpo o nombre de adjunto.");
}

if (mailType === "cuestionario" && !attachmentInfo.has_excel_attachment) {
  warnings.push("El correo parece ser de cuestionario, pero no se ha encontrado adjunto Excel.");
}

if (mailType === "followup" && !body) {
  warnings.push("El correo parece ser follow-up, pero el cuerpo del mensaje está vacío.");
}

return {
  json: {
    ...json,

    mail_type: mailType,
    case_id: caseId,

    email_subject: normalizedSubject,
    email_subject_original: subject,
    email_subject_b64: subjectB64,

    email_body: body,
    email_body_b64: bodyB64,

    from_email: fromEmail,
    received_at: new Date().toISOString(),

    attachment_b64: attachmentInfo.attachment_b64,
    attachment_filename: attachmentInfo.attachment_filename,
    attachment_binary_key: attachmentInfo.attachment_binary_key,
    has_excel_attachment: attachmentInfo.has_excel_attachment,
    attachments_detected: attachmentInfo.attachments,

    intake_warnings: warnings
  },
  binary: $input.item.binary
};

const stdout = $json.stdout || "";

let parsed;

try {
  parsed = JSON.parse(stdout);
} catch (e) {
  throw new Error("No se pudo parsear la salida del guardado de respuesta proveedor: " + stdout);
}

return {
  json: parsed
};

