=python - <<'PY'
import json
from pathlib import Path

case_id = {{ JSON.stringify($json.case_id) }}

base = Path("/data/cases") / case_id
analysis_dir = base / "03_analysis"
followup_dir = base / "04_followups" / "round_001"

scoring_preliminary_path = analysis_dir / "scoring_preliminary.json"
followups_pending_path = analysis_dir / "followups_pending.json"
provider_response_path = followup_dir / "provider_response_parsed.json"

if not scoring_preliminary_path.exists():
    raise Exception(f"No existe {scoring_preliminary_path}")

if not provider_response_path.exists():
    raise Exception(f"No existe {provider_response_path}")

scoring = json.loads(scoring_preliminary_path.read_text(encoding="utf-8"))
provider_response = json.loads(provider_response_path.read_text(encoding="utf-8"))

answers_by_question = provider_response.get("answers_by_question", {})
full_clean_response = provider_response.get("full_clean_response", "")

evaluations = scoring.get("question_evaluations", [])

pending_ids = set()

if followups_pending_path.exists():
    followups_pending = json.loads(followups_pending_path.read_text(encoding="utf-8"))

    for item in followups_pending.get("questions", []):
        qid = item.get("question_id", "")

        if qid == "Q_037-Q_040":
            pending_ids.update(["Q_037", "Q_038", "Q_039", "Q_040"])
        elif qid:
            pending_ids.add(qid)

# Fallback por si followups_pending está incompleto.
for ev in evaluations:
    try:
        score = int(ev.get("score"))
    except Exception:
        score = None

    if score == 2 or ev.get("requires_provider_followup") is True:
        pending_ids.add(ev.get("question_id", ""))

pending_ids = {qid for qid in pending_ids if qid}

items = []

has_structured_answers = len(answers_by_question) > 0

for ev in evaluations:
    qid = ev.get("question_id", "")

    if qid not in pending_ids:
        continue

    if has_structured_answers:
        provider_answer_for_q = answers_by_question.get(qid, "")
    else:
        provider_answer_for_q = full_clean_response

    items.append({
        "question_id": qid,
        "previous_evaluation": ev,
        "provider_followup_answer": provider_answer_for_q,
        "provider_response_detected": bool(provider_answer_for_q.strip()),
        "full_clean_provider_response": full_clean_response
    })

batch_size = 1
out_dir = analysis_dir / "followup_reanalysis_batches"
out_dir.mkdir(parents=True, exist_ok=True)

for old in out_dir.glob("batch_*.json"):
    old.unlink()

batches = []

for idx in range(0, len(items), batch_size):
    chunk = items[idx:idx + batch_size]
    batch_id = f"followup_batch_{idx // batch_size + 1:03d}"
    path = out_dir / f"{batch_id}.json"

    data = {
        "case_id": case_id,
        "followup_round": 1,
        "batch_id": batch_id,
        "questions": chunk,
        "rule": "Máximo 1 ronda automática. Si tras esta respuesta sigue sin quedar claro, el score final será 1."
    }

    path.write_text(
        json.dumps(data, ensure_ascii=False, indent=2),
        encoding="utf-8"
    )

    batches.append({
        "batch_id": batch_id,
        "path": str(path),
        "question_count": len(chunk)
    })

print(json.dumps({
    "case_id": case_id,
    "followup_round": 1,
    "pending_question_count": len(items),
    "answers_detected": list(answers_by_question.keys()),
    "answers_count": len(answers_by_question),
    "batches": batches
}, ensure_ascii=False))
PY

