const stdout = $json.stdout || "";

let parsed;

try {
  parsed = JSON.parse(stdout);
} catch (e) {
  throw new Error("No se pudo parsear la creación de batches de follow-up: " + stdout);
}

if (!Array.isArray(parsed.batches)) {
  throw new Error("No se encontraron batches de follow-up en la salida: " + stdout);
}

return parsed.batches.map(batch => ({
  json: {
    case_id: parsed.case_id,
    followup_round: parsed.followup_round,
    batch_id: batch.batch_id,
    batch_path: batch.path,
    question_count: batch.question_count
  }
}));

const stdout = $json.stdout || "";
let batchData;

try {
  batchData = JSON.parse(stdout);
} catch (e) {
  throw new Error("No se pudo parsear batch de follow-up: " + stdout);
}

/*
  IMPORTANTE:
  Este nombre debe coincidir EXACTAMENTE con el nombre de la tool en n8n.
*/
const RAG_TOOL_NAME = "risk_catalog_search";
const RAG_COLLECTION_EXPECTED = "tfm_rag_manual_agent";

function truncateText(value, maxLength = 700) {
  const text = String(value || "").trim();

  if (text.length <= maxLength) return text;

  return text.slice(0, maxLength).trim() + "...";
}

function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function normalizeQid(value) {
  const text = String(value || "").toUpperCase().trim();
  const match = text.match(/Q[\s_\-]?(\d{1,3})/i) || text.match(/(\d{1,3})/);

  if (!match) return "";

  const num = match[1] || match[0];

  return `Q_${String(Number(num)).padStart(3, "0")}`;
}

function isEmptyOrWeakAnswer(value) {
  const text = normalizeText(value);

  if (!text) return true;

  const weakSignals = [
    "detallar",
    "por especificar",
    "pendiente",
    "a consultar",
    "consultar con cliente",
    "depende",
    "por establecer",
    "se puede generar",
    "no se aporta",
    "sin evidencia",
    "no disponemos todavia",
    "no disponemos todavía",
    "pendiente de validacion",
    "pendiente de validación",
    "en proceso",
    "no aprobado",
    "no documentado",
    "por definir",
    "se definira",
    "se definirá"
  ];

  return weakSignals.some(signal => text.includes(normalizeText(signal)));
}

function firstNonEmpty(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;

    const text = String(value).trim();

    if (text && text !== "undefined" && text !== "null") {
      return text;
    }
  }

  return "";
}

function getQuestionText(q) {
  const prev = q.previous_evaluation || {};

  return firstNonEmpty(
    q.question_text,
    q.question,
    q.text,
    prev.question_text,
    prev.question,
    prev.requisito,
    prev.control_text,
    prev.incumplimiento_identificado
  );
}

const questionsMap = new Map();

for (const q of batchData.questions || []) {
  const qid = normalizeQid(q.question_id);

  if (!qid) continue;

  if (questionsMap.has(qid)) {
    continue;
  }

  const prev = q.previous_evaluation || {};
  const providerFollowupAnswer = String(q.provider_followup_answer || "").trim();
  const providerResponseDetected =
    q.provider_response_detected === true &&
    providerFollowupAnswer.length > 0;

  const questionText = getQuestionText(q);
  const exactToken = `EXACT_QUESTION_ID_${qid}`;

  /*
    Query RAG:
    Empieza por token exacto + question_id.
    Esto ayuda a que Qdrant recupere la ficha correcta.
  */
  const toolInput = `${exactToken} ${qid} ${questionText}`.trim();

  questionsMap.set(qid, {
    question_id: qid,
    exact_rag_token: exactToken,

    /*
      Este es el valor que el agente debe pasar literalmente a la tool.
    */
    tool_input: toolInput,
    rag_search_query: toolInput,

    /*
      Refuerzo explícito para el agente.
    */
    tool_required: true,
    required_tool_name: RAG_TOOL_NAME,
    tool_call_instruction: `Llama a ${RAG_TOOL_NAME} con este input exacto antes de reanalizar: ${toolInput}`,

    previous_evaluation: {
      previous_score: prev.score,
      previous_score_type: prev.score_type,
      previous_answer_summary: truncateText(prev.answer_summary || "", 350),
      previous_decision_reason: truncateText(prev.decision_reason || "", 450),
      previous_provider_answer: truncateText(prev.provider_answer || "", 300),
      previous_provider_details: truncateText(prev.provider_details || "", 450)
    },

    provider_followup: {
      provider_response_detected: providerResponseDetected,
      provider_followup_answer: truncateText(providerFollowupAnswer, 1200),
      provider_followup_answer_is_weak_or_empty: isEmptyOrWeakAnswer(providerFollowupAnswer)
    },

    risk_context_from_previous_evaluation: {
      risk_name: prev.risk_name || "",
      incumplimiento_identificado: truncateText(prev.incumplimiento_identificado || "", 400),
      mitigation: truncateText(prev.mitigation || "", 450)
    }
  });
}

const compactQuestions = Array.from(questionsMap.values());

if (compactQuestions.length === 0) {
  throw new Error(
    "No se encontraron preguntas válidas para reanalizar en follow-up. Batch recibido: " +
    JSON.stringify(batchData).slice(0, 2000)
  );
}

const requiredToolCalls = compactQuestions.map((q, index) => ({
  order: index + 1,
  question_id: q.question_id,
  tool_name: RAG_TOOL_NAME,
  input: q.tool_input
}));

const toolCallPlanText = requiredToolCalls
  .map(call => `${call.order}. ${call.tool_name} con input: "${call.input}"`)
  .join("\n");

const systemPrompt = `
INSTRUCCIÓN PRIORITARIA ABSOLUTA:
Esta es una tarea TOOL-FIRST de reanálisis de follow-up.

Tu primera acción obligatoria NO es responder.
Tu primera acción obligatoria es llamar a la herramienta ${RAG_TOOL_NAME}.

No puedes reanalizar ninguna pregunta antes de usar la herramienta ${RAG_TOOL_NAME}.
No puedes devolver el JSON final antes de haber usado la herramienta ${RAG_TOOL_NAME}.
No puedes responder usando conocimiento general, memoria o inferencias sin RAG.
No puedes decidir solo con la evaluación anterior.
No puedes decidir solo con la respuesta adicional del proveedor.

Si tienes una pregunta a reanalizar, debes hacer exactamente este ciclo:
1. Llamar a ${RAG_TOOL_NAME}.
2. Leer la ficha recuperada.
3. Comprobar que metadata.question_id coincide con question_id.
4. Analizar únicamente la respuesta adicional del proveedor.
5. Decidir final_score = 1 o final_score = 3.
6. Devolver JSON final.

Eres un agente experto en análisis de riesgos técnicos de ciberseguridad para soluciones SaaS.

Estás reanalizando preguntas que quedaron con score = 2 tras una primera evaluación.

HERRAMIENTA DISPONIBLE:
Nombre exacto de la herramienta:
${RAG_TOOL_NAME}

Uso de la herramienta:
- La herramienta recupera la ficha oficial del catálogo de riesgos.
- La herramienta debe usarse antes de reanalizar cada pregunta.
- La herramienta recibe un único input textual.
- Ese input debe ser exactamente el valor tool_input de la pregunta.
- No cambies, resumas ni reformules tool_input.
- No llames a la herramienta con otro texto diferente.

CONTRATO DE USO RAG:
- Debes realizar una llamada independiente a ${RAG_TOOL_NAME} por cada question_id.
- Si hay 1 pregunta, debes hacer 1 llamada.
- Si hay 3 preguntas, debes hacer 3 llamadas.
- Si no usas la herramienta para una pregunta, la evaluación de esa pregunta es inválida.
- Si la herramienta no devuelve ficha válida después de llamarla, final_score = 1 y añade una nota en batch_validation_notes.
- Si metadata.question_id no coincide exactamente con question_id, descarta la ficha, final_score = 1 y añade una nota en batch_validation_notes.
- No uses documentos de otra pregunta.
- No inventes reglas que no estén en la ficha recuperada o en la evaluación anterior.

QUÉ CONTIENE LA FICHA RAG:
- reglas de scoring
- controles asociados
- incumplimientos
- condiciones de cumplimiento
- condiciones de ambigüedad
- reglas condicionales
- severidad
- mitigación

OBJETIVO DEL REANÁLISIS:
Decidir si la respuesta adicional del proveedor resuelve definitivamente la duda.

REGLA PRINCIPAL:
- Analiza únicamente provider_followup.provider_followup_answer como respuesta nueva del proveedor.
- No analices previous_decision_reason como si fuera respuesta nueva.
- No analices previous_answer_summary como si fuera respuesta nueva.
- No analices previous_provider_answer como si fuera respuesta nueva.
- No analices previous_provider_details como si fuera respuesta nueva.
- La evaluación anterior solo sirve como contexto de por qué se pidió aclaración.

SCORES PERMITIDOS:
- final_score = 3: la respuesta adicional confirma claramente que el control está implantado y cubre el alcance requerido.
- final_score = 1: la respuesta adicional confirma incumplimiento, sigue siendo ambigua, queda pendiente, está en proceso o no aporta evidencia suficiente.
- No devuelvas final_score = 2.

REGLA DE UNA SOLA RONDA:
- Esta es la única ronda automática de follow-up.
- Si la respuesta sigue siendo ambigua, incompleta, genérica, "por especificar", "detallar", "depende", "pendiente", "se puede generar", "en proceso", "no aprobado" o "no documentado", devuelve final_score = 1.
- No solicites otro follow-up.
- No generes nuevas preguntas al proveedor.

REGLAS GENERALES DE DECISIÓN:
- Si provider_response_detected es false, final_score = 1.
- Si provider_followup_answer está vacío, final_score = 1.
- Si provider_followup_answer solo contiene texto genérico, final_score = 1.
- Si provider_followup_answer aporta tecnología, configuración, alcance y confirmación clara del control, final_score = 3.
- Si el proveedor dice que algo está en proceso, pendiente, no aprobado o no documentado, final_score = 1.
- Si el proveedor indica que no existe el control, final_score = 1.
- Si el proveedor indica una medida equivalente suficiente, final_score = 3.

REGLAS ESPECÍFICAS:
- Q_007: final_score = 3 si se confirma identificador único/personal por usuario y ausencia de cuentas compartidas. Si no queda claro, final_score = 1.
- Q_008: final_score = 3 si se describe proceso o herramienta para identificar y gestionar roles de administración. Si es genérico, final_score = 1.
- Q_011: final_score = 3 si se confirma repositorio centralizado real o integración IAM/LDAP/AD. Si es solo base local y el control exigía centralización corporativa, final_score = 1.
- Q_012: final_score = 3 si se describe procedimiento de altas, bajas y modificaciones con responsables y plazos. Si falta procedimiento o plazos, final_score = 1.
- Q_013: final_score = 3 si se confirma RBAC/perfiles con roles definidos y asignación de permisos. Si falta granularidad o detalle, final_score = 1.
- Q_019: final_score = 3 si se confirma hash seguro de contraseñas, por ejemplo bcrypt, Argon2, PBKDF2, salt único o mecanismo equivalente. Si no hay algoritmo o mecanismo claro, final_score = 1.
- Q_021: final_score = 3 si se confirma timeout, aplicabilidad a usuarios/roles y si es configurable o suficientemente gestionado. Si no queda claro, final_score = 1.
- Q_023: final_score = 3 si se confirma TLS 1.2 o TLS 1.3 y que SSL/TLS 1.0/TLS 1.1 están deshabilitados. Si no queda claro, final_score = 1.
- Q_028: final_score = 3 si se confirma algoritmo de cifrado robusto para backups o datos en reposo, por ejemplo AES-256, y alcance suficiente. Si no hay algoritmo claro, final_score = 1.
- Q_029: final_score = 3 si se confirma HTTPS con TLS 1.2 o superior y protocolos/cifrados inseguros deshabilitados. Si solo dice SSL o no concreta versiones, final_score = 1.
- Q_030: final_score = 3 si se detalla proceso de backup, retención, ubicación, integridad y restauración. Si faltan elementos clave, final_score = 1.
- Q_031: final_score = 3 solo si se aportan valores RTO/RPO claros o documentación equivalente aprobada. Si depende del problema o no hay valores cerrados, final_score = 1.
- Q_032: final_score = 3 solo si existe política de retención documentada/aprobada con periodos o criterios claros, medidas de seguridad y accesos. Si está en proceso o pendiente, final_score = 1.
- Q_034: final_score = 3 solo si se confirma proceso estandarizado/documentado de finalización y baja. Si depende del proveedor/terceros o está pendiente de confirmar, final_score = 1.
- Q_036: final_score = 3 si se detalla devolución de datos, formatos, integridad y plazos. Si falta detalle técnico, final_score = 1.
- Q_045: final_score = 3 si se confirma aislamiento lógico/físico de entornos y no uso de datos reales o uso anonimizado. Si no queda claro, final_score = 1.
- Q_057: final_score = 3 si se describen procedimientos de comunicación y escalado de incidentes con responsables/canales/criterios. Si es genérico, final_score = 1.

FORMATO:
Después de usar la herramienta, devuelve únicamente JSON válido.
No uses Markdown.
No escribas texto fuera del JSON.
No uses bloques de código.
El primer carácter de la respuesta final debe ser {.
El último carácter de la respuesta final debe ser }.

REGLAS DE SALIDA:
- Devuelve una evaluación por cada pregunta recibida.
- No inventes preguntas.
- No omitas preguntas.
- No devuelvas final_score = 2.
- final_score_type solo puede ser "non_compliance" o "compliant".
- resolved_by_provider debe ser true solo si final_score = 3.
- answer_summary máximo 25 palabras.
- decision_reason máximo 40 palabras.
- Incluye rag_used y rag_retrieved_question_id si has podido identificarlo.
`;

