function getRawModelOutput(itemJson) {
  let raw =
    itemJson.output ||
    itemJson.text ||
    itemJson.response ||
    itemJson.result ||
    itemJson.message ||
    itemJson.data ||
    "";

  if (raw && typeof raw === "object") {
    if (raw.output) raw = raw.output;
    else if (raw.text) raw = raw.text;
    else if (raw.response) raw = raw.response;
    else if (raw.message) raw = raw.message;
    else if (raw.content) raw = raw.content;
    else raw = JSON.stringify(raw);
  }

  if (typeof raw !== "string") {
    raw = JSON.stringify(raw);
  }

  return raw.trim();
}

function extractJsonObject(raw) {
  raw = String(raw || "")
    .replace(/^```json/i, "")
    .replace(/^```/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(raw);
  } catch (e) {}

  const first = raw.indexOf("{");
  const last = raw.lastIndexOf("}");

  if (first === -1 || last === -1 || last <= first) {
    throw new Error("No se encontró JSON en la respuesta del modelo: " + raw);
  }

  const candidate = raw.slice(first, last + 1);

  try {
    return JSON.parse(candidate);
  } catch (e) {
    throw new Error("Se encontró un bloque JSON, pero no era JSON válido: " + candidate);
  }
}

function normalizeQid(value) {
  return String(value || "").trim().toUpperCase();
}

function getPreviousPromptItem(expectedBatchId) {
  const possibleNames = [
    "Code - Construir prompt follow-up",
    "Code in JavaScript3",
    "Code in JavaScript2",
    "Code in JavaScript1",
    "Code in JavaScript",
    "Code"
  ];

  const currentIndex = typeof $itemIndex !== "undefined" ? $itemIndex : 0;

  for (const name of possibleNames) {
    try {
      const items = $items(name);

      if (!items || !Array.isArray(items)) continue;

      if (items[currentIndex]?.json) {
        const candidate = items[currentIndex].json || {};
        const candidateBatchId = candidate.batch_id || candidate.batch_data?.batch_id || "";

        if (
          candidate.batch_data &&
          (!expectedBatchId || candidateBatchId === expectedBatchId)
        ) {
          return candidate;
        }
      }

      if (expectedBatchId) {
        for (const item of items) {
          const candidate = item.json || {};
          const candidateBatchId = candidate.batch_id || candidate.batch_data?.batch_id || "";

          if (candidate.batch_data && candidateBatchId === expectedBatchId) {
            return candidate;
          }
        }
      }

      for (const item of items) {
        const candidate = item.json || {};

        if (candidate.batch_data) {
          return candidate;
        }
      }
    } catch (e) {}
  }

  return {};
}

function normalizeFinalScore(value) {
  const score = Number(value);

  if (score === 3) return 3;

  return 1;
}

function normalizeEvaluation(ev) {
  const qid = normalizeQid(ev.question_id);
  const finalScore = normalizeFinalScore(
    ev.final_score !== undefined ? ev.final_score : ev.score
  );

  return {
    question_id: qid,
    final_score: finalScore,
    final_score_type: finalScore === 3 ? "compliant" : "non_compliance",
    answer_summary: ev.answer_summary || "",
    decision_reason: ev.decision_reason || "",
    resolved_by_provider: finalScore === 3
  };
}

function createFallbackEvaluation(qid, reason) {
  return {
    question_id: qid,
    final_score: 1,
    final_score_type: "non_compliance",
    answer_summary: "No se ha podido aplicar una resolución concluyente del follow-up.",
    decision_reason: reason || "Al existir una única ronda automática de follow-up, se fuerza incumplimiento.",
    resolved_by_provider: false
  };
}

const raw = getRawModelOutput($json);

let parsed;

try {
  parsed = extractJsonObject(raw);
} catch (e) {
  throw new Error(
    "El modelo no devolvió JSON válido en el follow-up. No se guardará un resultado vacío. Error: " +
    e.message +
    "\nRAW:\n" +
    raw.slice(0, 2000)
  );
}

if (!Array.isArray(parsed.question_evaluations)) {
  throw new Error(
    "El JSON del modelo no contiene question_evaluations como array. No se guardará resultado vacío. JSON: " +
    JSON.stringify(parsed).slice(0, 2000)
  );
}

if (parsed.question_evaluations.length === 0) {
  throw new Error(
    "El modelo devolvió question_evaluations vacío. No se guardará resultado vacío. RAW: " +
    raw.slice(0, 2000)
  );
}

const parsedBatchId = parsed.batch_id || "";
const promptItem = getPreviousPromptItem(parsedBatchId);
const batchData = promptItem.batch_data || {};

const caseId =
  parsed.case_id ||
  batchData.case_id ||
  promptItem.case_id ||
  "";

const batchId =
  parsed.batch_id ||
  batchData.batch_id ||
  promptItem.batch_id ||
  "";

const previousByQuestion = {};

for (const q of batchData.questions || []) {
  const qid = normalizeQid(q.question_id);
  if (qid) {
    previousByQuestion[qid] = q.previous_evaluation || {};
  }
}

const expectedIds = Object.keys(previousByQuestion);

const byId = {};

for (const ev of parsed.question_evaluations) {
  const qid = normalizeQid(ev.question_id);

  if (!qid) continue;

  // Si tenemos batch_data, filtramos por preguntas esperadas.
  // Si no lo tenemos, NO filtramos, porque si filtramos con expectedIds vacío
  // nos cargamos todas las evaluaciones válidas del modelo.
  if (expectedIds.length > 0 && !expectedIds.includes(qid)) {
    continue;
  }

  byId[qid] = normalizeEvaluation(ev);
}

// Si tenemos batch_data y el modelo omitió alguna pregunta,
// la metemos como score 1 por la regla de una sola ronda.
if (expectedIds.length > 0) {
  for (const qid of expectedIds) {
    if (!byId[qid]) {
      byId[qid] = createFallbackEvaluation(
        qid,
        "El modelo omitió esta pregunta en el reanálisis de follow-up. Se fuerza incumplimiento."
      );
    }
  }
}

const questionEvaluations = Object.values(byId);

if (questionEvaluations.length === 0) {
  throw new Error(
    "Tras normalizar, question_evaluations ha quedado vacío. Esto no debe guardarse. " +
    "Revisa el output del AI Agent y el nombre del nodo 'Code - Construir prompt follow-up'. RAW: " +
    raw.slice(0, 2000)
  );
}

const normalized = {
  case_id: caseId,
  batch_id: batchId,
  followup_round: 1,
  question_evaluations: questionEvaluations,
  batch_validation_notes: parsed.batch_validation_notes || [],
  normalizer_debug: {
    raw_model_output_preview: raw.slice(0, 500),
    parsed_question_count: parsed.question_evaluations.length,
    normalized_question_count: questionEvaluations.length,
    expected_question_count: expectedIds.length,
    expected_question_ids: expectedIds,
    normalized_question_ids: questionEvaluations.map(ev => ev.question_id),
    prompt_batch_data_found: Object.keys(batchData).length > 0
  }
};

const b64 = Buffer.from(
  JSON.stringify(normalized, null, 2),
  "utf8"
).toString("base64");

return {
  json: {
    case_id: normalized.case_id,
    batch_id: normalized.batch_id,
    followup_round: 1,
    followup_reanalysis: normalized,
    followup_reanalysis_b64: b64,
    raw_model_output: raw,
    normalized_question_count: questionEvaluations.length,
    normalized_question_ids: questionEvaluations.map(ev => ev.question_id)
  }
};

