    candidates.sort(reverse=True)
    return candidates[0][1]

def norm(value):
    return str(value or "").strip()

def clean_text(value):
    text = norm(value)
    text = re.sub(r"\s+", " ", text)
    return text.strip()

def normalize_level(value):
    v = norm(value).upper()

    if "ALTO" in v:
        return "ALTO"

    if "MEDIO" in v:
        return "MEDIO"

    if "BAJO" in v:
        return "BAJO"

    return ""

LEVEL_RANK = {
    "": 0,
    "BAJO": 1,
    "MEDIO": 2,
    "ALTO": 3
}

def max_level(levels):
    result = ""

    for level in levels:
        level = normalize_level(level)

        if LEVEL_RANK.get(level, 0) > LEVEL_RANK.get(result, 0):
            result = level

    return result

def mitigation_time(level):
    level = normalize_level(level)

    if level == "ALTO":
        return "3 meses"

    if level == "MEDIO":
        return "12 meses"

    if level == "BAJO":
        return "Pte."

    return ""

def risk_color(level):
    level = normalize_level(level)

    if level == "ALTO":
        return "red"

    if level == "MEDIO":
        return "orange"

    if level == "BAJO":
        return "yellow"

    return "gray"

def unique_keep_order(values):
    out = []
    seen = set()

    for value in values:
        if isinstance(value, list):
            candidates = value
        else:
            candidates = [value]

        for candidate in candidates:
            text = clean_text(candidate)

            if not text:
                continue

            key = text.lower()

            if key not in seen:
                seen.add(key)
                out.append(text)

    return out

def as_list(value):
    if value is None:
        return []

    if isinstance(value, list):
        return value

    if isinstance(value, str):
        parts = re.split(r"[;\n]+", value)
        return [p.strip() for p in parts if p.strip()]

    return [str(value)]

def is_empty_or_pending(value):
    text = str(value or "").strip().lower()

    if not text:
        return True

    if text in {
        "n/a",
        "#n/a",
        "na",
        "null",
        "none",
        "undefined",
        "pendiente",
        "pendiente de confirmar"
    }:
        return True

