function text(value) {
  return String(value ?? "").replace(/\s+/g, " ").trim();
}

function yesNo(value) {
  if (value === true) return "sí";
  if (value === false) return "no";
  return text(value) || "no indicado";
}

function arr(value) {
  if (!value) return [];
  if (Array.isArray(value)) return value.map(v => text(v)).filter(Boolean);
  return [text(value)].filter(Boolean);
}

function truncate(value, maxLength = 900) {
  const t = text(value);

  if (t.length <= maxLength) return t;

  return t.slice(0, maxLength).trim() + "...";
}

function getQuestionFacts(items, maxItems = 18) {
  return (items || [])
    .slice(0, maxItems)
    .map(q => {
      return {
        question_id: q.question_id || "",
        score: q.score,
        score_type: q.score_type || "",
        level: q.level || "",
        provider_answer: truncate(q.provider_answer || "", 350),
        provider_details: truncate(q.provider_details || "", 500),
        answer_summary: truncate(q.answer_summary || "", 350),
        decision_reason: truncate(q.decision_reason || "", 450),
        risk_name: q.risk_name || "",
        incumplimiento_identificado: truncate(q.incumplimiento_identificado || "", 500),
        mitigation: truncate(q.mitigation || "", 500)
      };
    });
}

function getGroup(name) {
  return reportPack.platform_characteristics_input?.[name] || [];
}

