function getRawModelOutput(itemJson) {
  let raw =
    itemJson.output ||
    itemJson.text ||
    itemJson.response ||
    itemJson.result ||
    itemJson.message ||
    itemJson.data ||
    "";

  if (raw && typeof raw === "object") {
    if (raw.output) raw = raw.output;
    else if (raw.text) raw = raw.text;
    else if (raw.response) raw = raw.response;
    else if (raw.message) raw = raw.message;
    else if (raw.content) raw = raw.content;
    else raw = JSON.stringify(raw);
  }

  return String(raw || "").trim();
}

function extractJsonObject(raw) {
  raw = String(raw || "")
    .replace(/^```json/i, "")
    .replace(/^```/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(raw);
  } catch (e) {}

  const first = raw.indexOf("{");
  const last = raw.lastIndexOf("}");

  if (first === -1 || last === -1 || last <= first) {
    throw new Error("No se encontró JSON en la respuesta del agente: " + raw);
  }

  return JSON.parse(raw.slice(first, last + 1));
}

function decodeB64Json(value) {
  if (!value) return null;

  try {
    return JSON.parse(Buffer.from(String(value), "base64").toString("utf8"));
  } catch (e) {
    return null;
  }
}

function getPreviousPromptItem() {
  const currentIndex = typeof $itemIndex !== "undefined" ? $itemIndex : 0;

  if ($json.report_pack) {
    return $json;
  }

  if ($json.report_pack_b64) {
    const decoded = decodeB64Json($json.report_pack_b64);
    if (decoded) {
      return {
        ...$json,
        report_pack: decoded
      };
    }
  }

  const possibleNames = [
    "Code - Construir prompt redacción informe",
    "Code in JavaScript5",
    "Code in JavaScript6",
    "Code in JavaScript4",
    "Code in JavaScript3",
    "Code in JavaScript2",
    "Code in JavaScript1",
    "Code in JavaScript",
    "Code"
  ];

  for (const name of possibleNames) {
    try {
      const items = $items(name);

      if (items?.[currentIndex]?.json?.report_pack) {
        return items[currentIndex].json;
      }

      if (items?.[currentIndex]?.json?.report_pack_b64) {
        const decoded = decodeB64Json(items[currentIndex].json.report_pack_b64);
        if (decoded) {
          return {
            ...items[currentIndex].json,
            report_pack: decoded
          };
        }
      }

      if (items) {
        for (const item of items) {
          if (item.json?.report_pack) return item.json;

          if (item.json?.report_pack_b64) {
            const decoded = decodeB64Json(item.json.report_pack_b64);
            if (decoded) {
              return {
                ...item.json,
                report_pack: decoded
              };
            }
          }
        }
      }
    } catch (e) {}
  }

  return {};
}

function normalizeText(value) {
  if (value === null || value === undefined) return "";

  if (typeof value === "object") {
    if (Array.isArray(value)) {
      return value
        .map(v => normalizeText(v))
        .filter(Boolean)
        .join(" ");
    }

    return Object.entries(value)
      .map(([key, val]) => {
        const cleanVal = normalizeText(val);
        if (!cleanVal) return "";
        const cleanKey = String(key || "")
          .replace(/_/g, " ")
          .trim();
        return `${cleanKey}: ${cleanVal}.`;
      })
      .filter(Boolean)
      .join(" ");
  }

  return String(value || "")
    .replace(/\s+/g, " ")
    .replace(/\s+\./g, ".")
    .replace(/\.\s*\./g, ".")
    .trim();
}

function isWeakText(value) {
  const text = normalizeText(value).toLowerCase();

  if (!text) return true;

  const weakExact = [
    "pendiente de confirmar",
    "información no aportada",
    "informacion no aportada",
    "por especificar",
    "detallar",
    "diarios",
    "diaria",
    "nunca",
    "no",
    "si",
    "sí",
    "otros"
  ];

  if (weakExact.includes(text)) return true;

  if (text.length < 55) return true;

  const wordCount = text.split(/\s+/).filter(Boolean).length;
  if (wordCount < 10) return true;

  return false;
}

function isObjectLike(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

