function normalizeObservations(value) {
  const out = [];

  for (const item of safeArray(value)) {
    if (!item) continue;

    if (typeof item === "string") {
      if (item.trim()) out.push(item.trim());
      continue;
    }

    if (typeof item === "object") {
      const field = item.field || item.campo || "";
      const reason = item.reason || item.motivo || item.description || "";
      const text = normalizeText([field, reason].filter(Boolean).join(": "));
      if (text) out.push(text);
      continue;
    }

    out.push(String(item));
  }

  return out;
}

