  },
  binary
};

function extractJsonObject(value, rawGroq = {}) {
  if (value && typeof value === "object") {
    return value;
  }

  const raw = String(value || "").trim();

  if (!raw) {
    throw new Error("Respuesta vacía de Groq en follow-up.");
  }

  const finishReason =
    rawGroq.choices?.[0]?.finish_reason ||
    rawGroq.choices?.[0]?.finishReason ||
    "";

  let cleaned = raw
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    // seguimos con extracción por llaves
  }

  const first = cleaned.indexOf("{");
  const last = cleaned.lastIndexOf("}");

  if (first === -1 || last === -1 || last <= first) {
    throw new Error(
      "No se encontró objeto JSON en la respuesta de Groq follow-up. " +
      "finish_reason=" + finishReason + ". Respuesta parcial: " +
      cleaned.slice(0, 1500)
    );
  }

  const candidate = cleaned.slice(first, last + 1);

  try {
    return JSON.parse(candidate);
  } catch (e) {
    const seemsTruncated =
      finishReason === "length" ||
      !candidate.trim().endsWith("}") ||
      (candidate.match(/"/g) || []).length % 2 !== 0;

    if (seemsTruncated) {
      throw new Error(
        "Groq devolvió un JSON incompleto/cortado en follow-up. " +
        "Solución: sube max_completion_tokens a 2000, pon reasoning_effort='low', " +
        "include_reasoning=false, o reduce el batch size de follow-up a 3. " +
        "Error JSON: " + e.message +
        "\nRespuesta parcial:\n" +
        candidate.slice(0, 2500)
      );
    }

    throw new Error(
      "Groq devolvió texto en follow-up, pero no se pudo parsear como JSON. Error: " +
      e.message +
      "\nRespuesta parcial:\n" +
      candidate.slice(0, 2500)
    );
  }
}

function getGroqContent(json) {
  if (json.choices?.[0]?.message?.content) {
    return json.choices[0].message.content;
  }

  if (json.choices?.[0]?.text) {
    return json.choices[0].text;
  }

  if (json.output_text) {
    return json.output_text;
  }

  if (json.text) {
    return json.text;
  }

  if (json.response) {
    return json.response;
  }

  if (json.output) {
    return json.output;
  }

  if (json.question_evaluations || json.evaluations || json.batch_id || json.case_id) {
    return json;
  }

  return "";
}

function getPromptItem() {
  const candidateNodeNames = [
    "Code in JavaScript3",
    "Code - Construir prompt follow-up",
    "Code - Construir prompt followup",
    "Code - Construir prompt reanalisis followup",
    "Code - Construir prompt reanálisis followup"
  ];

  for (const nodeName of candidateNodeNames) {
    try {
      const items = $items(nodeName);

      if (items && items[$itemIndex]?.json) {
        return items[$itemIndex].json;
      }

      if (items && items.length === 1 && items[0]?.json) {
        return items[0].json;
      }
    } catch (e) {
      // probar siguiente
    }
  }

  return {};
}

const content = getGroqContent($json);
const parsed = extractJsonObject(content, $json);

let promptItem = getPromptItem();

if (!promptItem.case_id && $json.case_id) {
  promptItem = $json;
}

